var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"합중국, 브라이트 포트 봉쇄지구 – 20:07:38\\n스캐빈저, 강습함 <color=#ffd34c>마타도르</color>\\nCSE Level <b>2+</b>","JPN":"合衆国、ブライトポート封鎖地区　–　20:07:38\\nスカベンジャー、強襲艦<color=#ffd34c>マタドール</color>\\nCSE Level<b>2+</b>","ENG":"The States, Bright Port Sealed Area – 20:07:38\\nScavengers, Assault Ship <color=#ffd34c>Matador</color>\\nCSE Level <b>2+</b>","TWN":"合眾國 布萊特港封鎖地區 – 20:07:38\\n清道夫，強襲艦 <color=#ffd34c>鬥牛士</color>\\nCSE Level <b>2+</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"오, 남의 집 쓰레기통을 뒤지는 일은 정말이지 적성에 안 맞아.","JPN":"ああ、他所んちのゴミ箱を漁るなんて本当に性に合わねえぜ。","ENG":"Oh, how I hate to go through someone else’s trash.","TWN":"吼唷，翻別人家的垃圾桶根本不是我會做的事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"리플레이서인지 뭔지 이미 폭삭 망했다며? 우린 왜 쉴 틈도 없이 여기서 뺑이를 치는 거야?","JPN":"リプレイサーとやらは完全に滅びたんだろ？　なんで俺らは休む間もなく、ここで雑用係をさせられるわけ？","ENG":"The Replacers are all gone now, right? Then why do we have to work our butt off here?","TWN":"克隆集團還什麼的，不是已經完蛋了嗎？為什麼我們還在這裡幹這種苦差事？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>리액터</color>를 찾아오라는 두목의 명령이다.","JPN":"<color=#ffd34c>リアクター</color>を探してこいというのがボスの命令だ。","ENG":"The boss wants us to find the <color=#ffd34c>reactor</color>.","TWN":"老大要我們來找<color=#ffd34c>反應爐</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"그리고 스캐빈저는 제일 센 놈이 대장이지. 불만이 있으면 두목에게 가서 말해.","JPN":"それに、スカベンジャーは一番強い奴が隊長だろ？　文句があるならボスに直接言え。","ENG":"And you know the strongest rules among us Scavengers. So if you have a problem, go talk to the boss.","TWN":"而且在清道夫裡，最強的人就是隊長！你有什麼意見的話，自己去找老大說。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"히히, 두목이랑 붙으면 나 응원해 줄 거야?","JPN":"ひひっ、ボスとやることになったら俺を応援してくれるか？","ENG":"Hehe, if I fight her, will you be on my side?","TWN":"嘿嘿，我跟老大打起來的話，你替我加油嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"시체는 수습해 주지. 네 몸뚱이에는 쓸 만한 부품들이 들어가 있으니까.","JPN":"まあ、死体は引き取ってやる。\\nお前の体には使えそうな部品が入っているからな。","ENG":"I will take care of your dead body. You'll probably have some useful parts left.","TWN":"我會替你收屍，畢竟你身上還有一些能用的零件。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"멀쩡하게 건질 수 있을지는 모르겠지만.","JPN":"使える状態で残っているかはわからないがな。","ENG":"Though I’m not sure if they'll be in good enough shape to be worth it.","TWN":"只是不確定老大會留你全屍嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이런, 네가 내 몸에 눈독 들이고 있는 줄은 상상도 못했네.","JPN":"おっと、お前が俺の体に興味があったなんて想像もしてなかったぜ。","ENG":"Oh, I didn’t know you were interested in my body.","TWN":"沒想到你這傢伙竟然覬覦我的身體！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"어때, 수확은 좀 있나?","JPN":"どうだ、収穫はあったか？","ENG":"How is it going?","TWN":"如何？有什麼收穫嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"오, 잘 왔어. 세뇨라. 안 그래도 부르러 갈 생각이었거든.","JPN":"おっ、いいところに来たなセニョーラ。ちょうど呼びにいくとこだったんだ。","ENG":"Hola, señorita. I was about to call you.","TWN":"喔，你來啦，Senora！正想去找老大呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"그 리액터라는 거 말이야, 정말 여기 있는 게 확실해?","JPN":"そのリアクターとやら、本当にここにあるのか？","ENG":"That reactor, is it really here?","TWN":"那個反應爐真的在這裡嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"우리 잘나신 의장 나리가 준 정보니 가능성이 있다고 봐야지.","JPN":"うちの立派な議長様からの情報だから、その可能性は高いだろう。","ENG":"The information is from our glorious chairman, so it’s highly likely.","TWN":"是我們偉大的議長大人說的，應該有點可信度吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭔 생각을 하는지 모를 녀석이긴 하지만 정보력만큼은 마스터도 인정하니까.","JPN":"腹の内はわからないが、情報収集力だけはマスターも認めたからな。","ENG":"I don’t know what’s on his mind, but even the Master respects his intel.","TWN":"雖然不知道他腦袋裡在想什麼，不過他的情報能力可是連主人也認可的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"가능성이래. 우리 엄마도 나더러 넌 커서 크게 될 가능성이 있다고 했지, 아마.","JPN":"可能性かよ。うちの母ちゃんも､俺が大人になったら\\nビッグになる可能性があるって言ってたぜ､たしか｡","ENG":"Quite so. My mom told me that I was likely to become a big shot when I grow up.","TWN":"可信度嗎？當初我媽說我長大後一定大有可為，我也覺得有點可信度。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"너희 두목은 고등기술의 소재를 받는 조건으로 평의회에 들어왔어.","JPN":"お前らのボスは高等技術の素材をもらう条件で評議会に入ったんだ｡","ENG":"Your boss joined the Council to receive high-tech materials.","TWN":"你們老大是以取得高等技術材料為條件，進到評議會的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그 대가로 너희들이 해야 하는 건 몸 쓰는 일이지.","JPN":"その見返りにお前らがやるべきことは、体を張ることさ。","ENG":"In exchange, you have to work out in the field. That’s the deal.","TWN":"老大出嘴，你們當然要出力囉！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그러니 CSE 레벨 오르는 것 때문에 들키기 전에 잔말 말고 어서 뭐라도 찾아내.","JPN":"だから、CSEレベルが上がってバレる前に、黙ってさっさと見つけ出せ。","ENG":"So find that reactor before the rising CSE Level draws someone else’s attention.","TWN":"所以在因為CSE等級上升而被發現前，廢話少說快點找！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"여긴 우리가 거들먹거리고 다니던 이면세계가 아니니까.","JPN":"ここは俺たちが幅をきかせてた裏世界じゃない。","ENG":"This is not the Counterside where we are in charge.","TWN":"這裡可不是我們的地盤，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"관리국이나 정규군 같은 아주 귀찮은 녀석들이 감시하고 있는 곳이라고.","JPN":"管理局や正規軍みたいなクソめんどくさい奴らが監視してる場所だからな。","ENG":"Forces like the Administration and regular armed forces are watching this place.","TWN":"這裡是由管理局，或軍隊那些麻煩的傢伙在監視的地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"기다려라. 수집가.","JPN":"待て、収集家。","ENG":"Wait, Collector.","TWN":"收藏家，等等。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L35_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"음? 뭐지?","JPN":"うん？　なんだ？","ENG":"Huh? What is it?","TWN":"嗯？幹嘛？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"정찰 보낸 부대원들 중에 교신이 끊어진 녀석들이 있다.","JPN":"偵察に行かせた部隊員の中に、交信が途絶えた奴らがいる。","ENG":"Some of my scouts are not responding.","TWN":"我們派出去偵察的隊員中，有些人的訊號中斷。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"냄새를 맡은 녀석이 있는 모양이군.","JPN":"匂いを嗅ぎ付けた奴がいるようだ。","ENG":"I think we’ve been caught.","TWN":"看來有人發現到不對勁"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"그럴 리가! 차폐는 완벽하게 해 뒀다구!","JPN":"おいおいまさか！　遮蔽は完璧だったはずだぜ！","ENG":"That can’t be! My shield was perfect!","TWN":"這怎麼可能！我明明有放好掩護！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아. 아. 마이크 테스트 중. 하나. 둘.","JPN":"チェックワンツー、マイクテスト中。","ENG":"Hello, hello, mic test. One, two.","TWN":"喂，喂，麥克風測試，1、2！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"안녕하신가, 친구 분들. 잠시 여권 검사 좀 해야겠는데.","JPN":"やあ、みんな。ちとパスポートを見せてもらうよ。","ENG":"Good day, my dear friends. I need to see your passports, please.","TWN":"各位朋友們，大家好，現在要檢查一下各位的護照。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"너는……. 뭐 하는 녀석이지? 용병이냐?","JPN":"お前は……何者だ？　傭兵か？","ENG":"Who are you? A mercenary?","TWN":"你是……誰啊？是傭兵嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그런 끔찍한 소릴 하다니, 아주 불쾌하군. 고철수집가.","JPN":"縁起でもないことを言うなよ、不愉快極まりないな。古鉄収集家。","ENG":"Why, that is very insulting, Junk Collector.","TWN":"那是什麼驚人的發言？！我不是很開心喔，廢鐵收藏家。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"기계수집가다. 얼간아.","JPN":"機械収集家だ、間抜け。","ENG":"It’s MACHINE Collector, you idiot.","TWN":"是機械收藏家啦，蠢蛋！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"나에 대해 알고 있는 걸 보니 알파트릭스 놈들이 보낸 건가?","JPN":"俺のことを知ってるってことは、アルファトリックスの奴らに送り込まれたのか？","ENG":"You must be from Alphatrix, if you know me.","TWN":"你竟然知道我的名字，那應該是阿爾法崔克斯的傢伙派你來的吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"하하, 그럴 리가.","JPN":"ハハ、まさか。","ENG":"Nah, you’re wrong.","TWN":"哈哈，怎麼可能！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"탈옥 사건으로 떠들썩할 때 지명수배가 걸린 걸 봤을 뿐이야.","JPN":"脱獄事件で騒がしかった時に指名手配書を見ただけさ。","ENG":"I saw your picture when you broke out of jail.","TWN":"我只是剛好在逃獄事件鬧得滿城風雨時，有看到你的通緝令而已。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그럼 어설프게 끼어들 생각 말고 꺼져. 나도 괜한 소란 일으키고 싶진 않아.","JPN":"それなら横槍を入れずにとっとと失せろ。俺も余計な騒ぎを起こしたくはない。","ENG":"Then keep your nose out of this. I don’t want any unnecessary trouble.","TWN":"既然如此，那你就罩子放亮點別礙事，我也沒有要鬧事的意思。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"하하하하하!","JPN":"アハハハハ！","ENG":"Hahahaha!","TWN":"哈哈哈哈哈！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아, 이런. 미안.","JPN":"ああ、ごめんごめん。","ENG":"Oh, oh, I’m sorry.","TWN":"哎呀～不好意思。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"방금 그 농담, 요 며칠 들었던 것 중에 제일 신선했어.","JPN":"今の冗談、ここ最近聞いた中で一番キレッキレだったよ。","ENG":"That was the funniest joke I’ve heard for quite some time.","TWN":"剛剛那個笑話是我近期聽到最好笑的一個。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아무튼, 여권이 없으면 협조 좀 해 주셔야겠는데.","JPN":"とにかく、パスポートが無いなら、少し協力してもらわないといけないな。","ENG":"Anyway, if you don’t have passports, you’ll have to come with me.","TWN":"總之你沒有護照的話，就麻煩配合一點。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"……꽤 질척거리는군.","JPN":"……ずいぶんしつこいな。","ENG":"Now that’s a nuisance.","TWN":"……還真是死纏爛打呢！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"좋아. 그럼 거기 옆에 있는 벨보이까지 합쳐서 면담이나 할까.","JPN":"まあいい。じゃあ、そこのベルボーイも入れて話し合いでもしようか。","ENG":"Okay, we’ll have an interview, and you can bring that bellboy along with you.","TWN":"好吧，那就和旁邊那個服務生一起搞定吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"동정표 받을 수 있게 울상 짓는 법이나 연습해 두시지.","JPN":"同情してもらえるように、泣き顔の練習でもしとけよ。","ENG":"Also, you’ll have to practice your apologies so that I might forgive you.","TWN":"勸你們趕快練習一下裝可憐，說不定能騙取我的同情。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이봐, 대령! 대체 무슨 짓이야!","JPN":"おい、大佐！　どういうことだ！","ENG":"Hey, Colonel! What are you doing?","TWN":"上校！你這是在做什麼！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"저 놈들은 이 바닥에서 아주 유명한 해적이야!","JPN":"あいつらはこの辺じゃ名の知れた海賊だぞ！","ENG":"They are super infamous pirates!","TWN":"那些傢伙可是在這裡惡名昭彰的海盜！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"얼마 전에는 알파트릭스의 핵심 부대도 낭패를 당했다는 소문까지 있어.","JPN":"先日、アルファトリックスの主力部隊でさえ痛い目に遭ったという噂もある。","ENG":"I even heard that they fought off Alphatrix’s core squad.","TWN":"我聽說之前阿爾法崔克斯派出的菁英部隊，也被他們打得落花流水欸！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"스캐빈저 놈들과 엮이면 좋을 게 없다고.","JPN":"スカベンジャーの奴らと関わったって、何もいいことなんてないぞ。","ENG":"It’s no good getting mixed up with those Scavengers.","TWN":"和那些清道夫扯上邊準沒好事！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"리플레이서 잔당만으로도 골치 아픈데 해적들한테까지 끌어들여서 어쩔 셈이야?!","JPN":"リプレイサーの残党だけでも頭が痛いのに、海賊まで巻き込んでどうするつもりだ！？","ENG":"We may have to deal with Replacer remnants, and now we have to fight pirates too?","TWN":"光是那些克隆集團的餘黨就已經夠頭疼的了，你還去招惹海盜，你到底想幹嘛？！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"너무 그렇게 불쌍한 표정 짓지 말라고, 메이슨 씨.","JPN":"そんな不甲斐ない顔するなよ、メイソンさん。","ENG":"What’s up with the long face, Mr. Mason?","TWN":"梅森，你不要一臉世界末日的樣子嘛。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"당신 같은 용병과는 달리 군인은 해적을 보면 박멸할 의무가 있거든.","JPN":"あんたみたいな傭兵とは違って、軍人は海賊を見つけたら撲滅する義務があるんだ。","ENG":"Unlike you mercenaries, I, a proper soldier, have a duty to get rid of pirates.","TWN":"我和你們這些傭兵不一樣，我是軍人，軍人看到海盜是有義務要制裁他們的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이런, 성질 급한 녀석들이군.","JPN":"やれやれ、せっかちな奴らだな。","ENG":"Oh, they really are quick-tempered.","TWN":"真是的，個性還真急！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그렇게 됐으니 조금만 더 고생해 달라고, 메이슨 씨.","JPN":"こうなった以上、もう少しだけ苦労してくれよ、メイソンさん。","ENG":"So, Mr. Mason, let’s get on with it.","TWN":"既然如此，那就只好麻煩你再辛苦一點囉，梅森。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……이래서 내가 군인 놈들을 싫어한다니까.","JPN":"……これだから俺は軍人どもが嫌いなんだ。","ENG":"... This is why I hate soldiers.","TWN":"……所以我才很討厭軍人的嘛！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"어이! 대령! 기다려!","JPN":"おい！　大佐！　待てよ！","ENG":"Hey, Colonel, Wait!","TWN":"喂！上校！等我一下啦！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};